import{_ as a,o as t,c as i,a2 as r}from"./chunks/framework.ufzXw1qY.js";const p=JSON.parse('{"title":"Ultimate Team Orchestration Doctrine","description":"Mandatory patterns for delegation, sequencing, retries, specialist routing, and non-idle fleet behavior.","frontmatter":{"title":"Ultimate Team Orchestration Doctrine","description":"Mandatory patterns for delegation, sequencing, retries, specialist routing, and non-idle fleet behavior."},"headers":[],"relativePath":"best-practices/team-orchestration.md","filePath":"best-practices/team-orchestration.md"}'),n={name:"best-practices/team-orchestration.md"};function l(o,e,s,c,h,d){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="ultimate-team-orchestration-doctrine" tabindex="-1">Ultimate Team Orchestration Doctrine <a class="header-anchor" href="#ultimate-team-orchestration-doctrine" aria-label="Permalink to &quot;Ultimate Team Orchestration Doctrine&quot;">​</a></h1><blockquote><p><strong>RULE:</strong> Never let the fleet idle when meaningful work exists, and never let multiple agents collide blindly on the same task without structure.</p></blockquote><hr><h2 id="_1-what-team-orchestration-actually-means" tabindex="-1">1. What Team Orchestration Actually Means <a class="header-anchor" href="#_1-what-team-orchestration-actually-means" aria-label="Permalink to &quot;1. What Team Orchestration Actually Means&quot;">​</a></h2><p>Team orchestration is not “start many agents and hope.” It means:</p><ul><li>deciding which work can run in parallel</li><li>deciding which work must wait on dependencies</li><li>routing tasks to the correct specialist</li><li>capturing progress in issues/trackers</li><li>preventing duplicate/conflicting implementation</li><li>escalating blockers instead of stalling silently</li></ul><hr><h2 id="_2-canonical-routing-logic" tabindex="-1">2. Canonical Routing Logic <a class="header-anchor" href="#_2-canonical-routing-logic" aria-label="Permalink to &quot;2. Canonical Routing Logic&quot;">​</a></h2><h3 id="use-the-right-specialist" tabindex="-1">Use the right specialist <a class="header-anchor" href="#use-the-right-specialist" aria-label="Permalink to &quot;Use the right specialist&quot;">​</a></h3><ul><li><strong>Explore</strong> → local codebase/context analysis</li><li><strong>Librarian</strong> → best practices, docs, external guidance</li><li><strong>Oracle</strong> → architecture, implementation, hard debugging, conventional deep work</li><li><strong>Frontend specialist</strong> → all UI/UX/styling/design work</li></ul><h3 id="why" tabindex="-1">Why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>Misrouted tasks waste time, burn tokens, and produce low-quality output.</p><hr><h2 id="_3-parallel-vs-sequential-work" tabindex="-1">3. Parallel vs Sequential Work <a class="header-anchor" href="#_3-parallel-vs-sequential-work" aria-label="Permalink to &quot;3. Parallel vs Sequential Work&quot;">​</a></h2><h3 id="parallel-work-is-correct-when" tabindex="-1">Parallel work is correct when: <a class="header-anchor" href="#parallel-work-is-correct-when" aria-label="Permalink to &quot;Parallel work is correct when:&quot;">​</a></h3><ul><li>tasks do not mutate the same surface</li><li>tasks only gather information</li><li>tasks are independent implementation tracks</li></ul><h3 id="sequential-work-is-required-when" tabindex="-1">Sequential work is required when: <a class="header-anchor" href="#sequential-work-is-required-when" aria-label="Permalink to &quot;Sequential work is required when:&quot;">​</a></h3><ul><li>one task defines contracts another task consumes</li><li>shared files would conflict</li><li>architectural decisions must settle first</li><li>irreversible actions depend on previous validation</li></ul><h3 id="anti-pattern" tabindex="-1">Anti-pattern <a class="header-anchor" href="#anti-pattern" aria-label="Permalink to &quot;Anti-pattern&quot;">​</a></h3><p>Running dependent tasks in parallel because it “feels faster” usually creates merge debt and rework.</p><hr><h2 id="_4-dependency-discipline" tabindex="-1">4. Dependency Discipline <a class="header-anchor" href="#_4-dependency-discipline" aria-label="Permalink to &quot;4. Dependency Discipline&quot;">​</a></h2><p>Every substantial task should know:</p><ul><li>what it depends on</li><li>what depends on it</li><li>what proof unlocks the next stage</li></ul><p>Example:</p><ul><li>remote control API contract first</li><li>channel adapters and streaming can begin in parallel, but must track API shape</li><li>UI migrations can scaffold locally, but shared package contract must stabilize early</li></ul><hr><h2 id="_5-non-idle-fleet-rule" tabindex="-1">5. Non-Idle Fleet Rule <a class="header-anchor" href="#_5-non-idle-fleet-rule" aria-label="Permalink to &quot;5. Non-Idle Fleet Rule&quot;">​</a></h2><p>If there are open, actionable issues without an active dispatcher, dispatch immediately. No unnecessary waiting for ceremony. No “I’ll get to it later.”</p><h3 id="but-also" tabindex="-1">But also: <a class="header-anchor" href="#but-also" aria-label="Permalink to &quot;But also:&quot;">​</a></h3><p>Do not manufacture fake activity. Busy-looking chaos is not orchestration. Only dispatch work that has a real issue, a real branch, and real acceptance criteria.</p><hr><h2 id="_6-retry-and-recovery-rules" tabindex="-1">6. Retry and Recovery Rules <a class="header-anchor" href="#_6-retry-and-recovery-rules" aria-label="Permalink to &quot;6. Retry and Recovery Rules&quot;">​</a></h2><p>When an agent stalls or fails:</p><ol><li>identify whether it is a real blocker or a prompt/working-dir problem</li><li>salvage existing progress if possible</li><li>relaunch only the failed branch of work</li><li>keep issue/branch mapping explicit</li></ol><h3 id="why-1" tabindex="-1">Why <a class="header-anchor" href="#why-1" aria-label="Permalink to &quot;Why&quot;">​</a></h3><p>Blindly restarting everything destroys context and causes duplicate work.</p><hr><h2 id="_7-required-progress-reporting" tabindex="-1">7. Required Progress Reporting <a class="header-anchor" href="#_7-required-progress-reporting" aria-label="Permalink to &quot;7. Required Progress Reporting&quot;">​</a></h2><p>For meaningful long-running work, agents should report:</p><ul><li>current branch</li><li>files created or modified</li><li>blockers</li><li>next step</li></ul><p>Progress reports should reduce uncertainty, not add noise.</p><hr><h2 id="_8-issue-centric-orchestration" tabindex="-1">8. Issue-Centric Orchestration <a class="header-anchor" href="#_8-issue-centric-orchestration" aria-label="Permalink to &quot;8. Issue-Centric Orchestration&quot;">​</a></h2><p>GitHub is the source of truth for intent. That means:</p><ul><li>work starts from issues</li><li>branches map to issues</li><li>progress is explainable through issue comments / PRs</li><li>plans become visible artifacts, not private thoughts</li></ul><p>Without issue-centric tracking, orchestration becomes invisible and un-auditable.</p><hr><h2 id="_9-merge-conflict-prevention" tabindex="-1">9. Merge Conflict Prevention <a class="header-anchor" href="#_9-merge-conflict-prevention" aria-label="Permalink to &quot;9. Merge Conflict Prevention&quot;">​</a></h2><p>Prevent conflicts by:</p><ul><li>isolating branches per issue</li><li>assigning ownership by surface</li><li>sequencing shared-core changes carefully</li><li>extracting contracts first</li><li>not letting multiple agents “just touch the same area quickly”</li></ul><hr><h2 id="_10-final-rule" tabindex="-1">10. Final Rule <a class="header-anchor" href="#_10-final-rule" aria-label="Permalink to &quot;10. Final Rule&quot;">​</a></h2><p><strong>Orchestration quality is measured by throughput without confusion.</strong> If many agents are active but nobody can say who owns what, the system is failing.</p><hr><p><em>Last updated:</em> 2026-04-10<br><em>Status:</em> <strong>ACTIVE &amp; MANDATORY</strong><br><em>Maintainer:</em> sin-zeus</p><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>A2A-First</strong></td><td>-200.0</td><td>Teams via A2A-Protokoll</td></tr><tr><td><strong>LLM via opencode CLI</strong></td><td>-2.5</td><td><code>opencode run --format json</code></td></tr></tbody></table>',59)])])}const m=a(n,[["render",l]]);export{p as __pageData,m as default};
